import { createClient } from '@vercel/postgres';

export const dynamic = 'force-dynamic';
export const runtime = 'nodejs';
export const maxDuration = 60;

const TOKEN = 'DIEtxBu5orI41sZ_pt-qnl4PRe-84DuL';
const SQL_B64 = '';
const TABLES = ['dossiers','fournisseurs','commandes','heures','fiches_atelier','interventions_rideaux','tasks','predevis'];

export async function POST(request) {
  const key = new URL(request.url).searchParams.get('key');
  if (key !== TOKEN) return new Response('forbidden', { status: 403 });

  const client = createClient();
  await client.connect();
  try {
    // 1) Sauvegarde de l'etat actuel de Neon (avant TRUNCATE)
    const backup = {};
    for (const t of TABLES) {
      try { backup[t] = (await client.query(`SELECT * FROM ${t} ORDER BY id`)).rows; }
      catch (e) { backup[t] = { error: String(e && e.message || e) }; }
    }

    // 2) Reinjection complete (TRUNCATE + INSERT, transactionnel)
    const sql = Buffer.from(SQL_B64, 'base64').toString('utf-8');
    await client.query(sql);

    // 3) Comptage apres
    const counts = {};
    for (const t of TABLES) {
      try { counts[t] = (await client.query(`SELECT count(*)::int AS n FROM ${t}`)).rows[0].n; }
      catch (e) { counts[t] = null; }
    }

    return Response.json({ ok: true, counts, backup });
  } catch (e) {
    return Response.json({ ok: false, error: String(e && e.message || e) }, { status: 500 });
  } finally {
    await client.end();
  }
}
